// Get input items from n8n
const items = $input.all();
const crypto = require('crypto');

// Fields that should be treated as booleans
const booleanFields = ["transparency", "enhance_prompt", "safety_checker"];

// Fields that should always be arrays
const arrayFields = ["init_images", "font_urls", "font_texts","super_resolution_refs"];
const removeFields = ["formmode"]
// Function to normalize field names: lowercase + underscores
function normalizeFieldName(name) {
  return name.toLowerCase().replace(/\s+/g, "_");
}
const outputItems = [];
const processId = crypto.randomUUID();
// Process each item
items.forEach(item => {
  const newJson = {};
  let init_limit = 4;
  let url = "https://api.replicate.com/v1/models/sourceful/riverflow-2.0-fast/predictions"
  if (
      typeof item.json.Model === "string" && item.json.Model === "pro"
    ) {
      url = "https://api.replicate.com/v1/models/sourceful/riverflow-2.0-pro/predictions"
      init_limit = 10;
    }
  for (let key in item.json) {
    let value = item.json[key];
    const newKey = normalizeFieldName(key);
    if (removeFields.includes(newKey)) continue;
    // Validate max_iterations
    if (newKey === "max_iterations") {
      if (value > 3) {
        throw new Error(`max_iterations cannot be greater than 3 (found ${value})`);
      }
    }
    if (newKey == "number_of_outputs"){
      if (value >4){
        throw new Error(`number of outputs cannot be greater than 4 (found ${value})`);
      }
    }

    // Convert comma-separated strings to arrays
    if (arrayFields.includes(newKey)) {
      if (typeof value === "string") {
        // Split by commas if any, remove empty strings, always make it an array
        value = value.split(",").map(s => s.trim()).filter(s => s.length > 0);
      }
      // Ensure single strings or empty values are also arrays
      if (!Array.isArray(value)) {
        value = value ? [value] : [];
      }

      // For font_urls, enforce max 2
      if (newKey === "font_urls" && value.length > 2) {
        throw new Error(`font_urls cannot have more than 2 entries (found ${value.length})`);
      }
      if(newKey == "init_images" && value.length > init_limit){
        throw new Error(`init_images cannot have more than ${init_limit} entries (found ${value.length})`);
      }
      if(newKey == "super_resolution_refs"&& value.length > 4){
        throw new Error(`super resolution refs cannot be more than 4 (found ${value.length})`);
      }
    }

    // Convert n8n boolean array-style to actual booleans
    if (booleanFields.includes(newKey)) {
      if (Array.isArray(value) && value.length === 1 && value[0].toLowerCase() === "true") {
        value = true;
      } else {
        value = false;
      }
    }

    // Assign normalized key/value
    newJson[newKey] = value;

  }
  newJson.url = url;
  newJson.processID = processId;
  const count = Number(newJson.number_of_outputs || 1);

  for (let i = 0; i < count; i++) {
    outputItems.push({
      json: JSON.parse(JSON.stringify(newJson))
    });
  }
  // Replace item.json with normalized version
  item.json = newJson;
});

// Return the modified input (compatible with n8n)
return outputItems;

