const items = $input.all();

if (items.length === 0) {
  return [];
}

// Return only the first item
return [items[0]];

const items = $input.all();

const outputUrls = [];

for (const item of items) {
  const output = item.json.output;

  if (typeof output === "string" && output.length > 0) {
    outputUrls.push(output);
  }
}

// Remove duplicates
const uniqueOutputs = [...new Set(outputUrls)];


return uniqueOutputs.map(url => ({
  json: { url }
}));

const items = $input.all();

// Extract process_id from any item that has it
const processId =
  items.find(i => i.json.process_id)?.json.process_id ?? null;

// Keep only items that are actual Replicate results
const resultItems = items.filter(
  item => Array.isArray(item.json.output)
);

// Build clean output
return resultItems.map(item => ({
  json: {
    process_id: processId,
    status: item.json.status,
    time: item.json.time,
    output_url: item.json.output[0] // Replicate returns array
  }
}));
